  1→import React, {useMemo, useState} from 'react';
  2→import {
  3→  Alert,
  4→  FlatList,
  5→  Pressable,
  6→  ScrollView,
  7→  StyleSheet,
  8→  Text,
  9→  View,
 10→} from 'react-native';
 11→import {useInfiniteQuery, useMutation} from '@tanstack/react-query';
 12→import {BottomTabScreenProps} from '@react-navigation/bottom-tabs';
 13→import {CompositeScreenProps} from '@react-navigation/native';
 14→import {NativeStackScreenProps} from '@react-navigation/native-stack';
 15→import {SafeAreaView} from 'react-native-safe-area-context';
 16→import {PostCard} from '../../components/PostCard/PostCard';
 17→import {PostCardSkeleton} from '../../components/SkeletonLoader';
 18→import {CommentModal} from '../../components/Comments';
 19→import {Chip} from '../../components/Chip';
 20→import {EmptyState} from '../../components/EmptyState';
 21→import {PenIcon} from '../../components/icons';
 22→import {useAuth} from '../../features/auth/AuthProvider';
 23→import {useTheme} from '../../theme/ThemeProvider';
 24→import {fonts, typeScale} from '../../theme/typography';
 25→import {spacing, radii, shadows} from '../../theme/spacing';
 26→import {
 27→  mobileApi,
 28→  type CursorPage,
 29→  type JournalItem,
 30→} from '../../lib/api/mobileApi';
 31→import {socialApi} from '../../lib/api/socialApi';
 32→import {queryClient} from '../../lib/queryClient';
 33→import {useBookmarkMutation, useRepostMutation} from '../../hooks/useSocialMutations';
 34→import {
 35→  extractPlainText,
 36→  extractBannerImage,
 37→  resolveCount,
 38→  getNextCursor,
 39→} from '../../lib/utils/journalHelpers';
 40→import type {MainTabParamList, RootStackParamList} from '../../navigation/types';
 41→
 42→type Props = CompositeScreenProps<
 43→  BottomTabScreenProps<MainTabParamList, 'Home'>,
 44→  NativeStackScreenProps<RootStackParamList>
 45→>;
 46→
 47→const PAGE_SIZE = 10;
 48→
 49→const QUICK_ACTIONS = [
 50→  {key: 'all', label: 'All'},
 51→  {key: 'journal', label: 'Journals'},
 52→  {key: 'canvas', label: 'Canvas'},
 53→  {key: 'freedom_wall', label: 'Freedom Wall'},
 54→  {key: 'universe', label: 'Universe'},
 55→] as const;
 56→
 57→export function HomeFeedScreen({navigation}: Props) {
 58→  const {user, session} = useAuth();
 59→  const {colors} = useTheme();
 60→  const token = session?.access_token ?? '';
 61→  const [refreshing, setRefreshing] = useState(false);
 62→  const [activeFilter, setActiveFilter] = useState('all');
 63→  const [commentModal, setCommentModal] = useState<{postId: string; receiverId?: string; commentCount: number} | null>(null);
 64→
 65→  const feedQuery = useInfiniteQuery({
 66→    queryKey: ['feed', user?.id],
 67→    queryFn: ({pageParam}) =>
 68→      mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
 69→    initialPageParam: null as string | null,
 70→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 71→  });
 72→
 73→  const reactionMutation = useMutation({
 74→    mutationFn: async ({
 75→      journalId,
 76→      receiverId,
 77→      reactionType,
 78→    }: {
 79→      journalId: string;
 80→      receiverId: string;
 81→      reactionType: string;
 82→    }) => {
 83→      if (!token) throw new Error('Please log in to react.');
 84→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 85→    },
 86→    onMutate: async ({journalId, reactionType}) => {
 87→      await queryClient.cancelQueries({queryKey: ['feed']});
 88→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(
 89→        ['feed', user?.id],
 90→      );
 91→      if (prev) {
 92→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(
 93→          ['feed', user?.id],
 94→          old => {
 95→            if (!old) return old;
 96→            return {
 97→              ...old,
 98→              pages: old.pages.map(page => ({
 99→                ...page,
100→                data: page.data.map(item => {
101→                  if (item.id !== journalId) return item;
102→                  const removing = item.user_reaction === reactionType;
103→                  const currentCount =
104→                    (item.reaction_count?.[0]?.count ??
105→                      item.like_count?.[0]?.count ??
106→                      item.likes_count ??
107→                      0) as number;
108→                  const delta = removing ? -1 : item.user_reaction ? 0 : 1;
109→                  return {
110→                    ...item,
111→                    user_reaction: removing ? null : reactionType,
112→                    has_liked: removing ? false : true,
113→                    like_count: [{count: Math.max(0, currentCount + delta)}],
114→                  };
115→                }),
116→              })),
117→            };
118→          },
119→        );
120→      }
121→      return {prev};
122→    },
123→    onError: (_err, _vars, context) => {
124→      if (context?.prev) {
125→        queryClient.setQueryData(['feed', user?.id], context.prev);
126→      }
127→    },
128→    onSettled: () => {
129→      queryClient.invalidateQueries({queryKey: ['feed']});
130→    },
131→  });
132→
133→  const bookmarkMutation = useBookmarkMutation(token, ['feed', user?.id]);
134→  const repostMutation = useRepostMutation(token);
135→
136→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
137→    if (!token) return;
138→    reactionMutation.mutate({journalId, receiverId, reactionType});
139→  };
140→
141→  const handleComment = (journalId: string, receiverId?: string, commentCount?: number) => {
142→    setCommentModal({postId: journalId, receiverId, commentCount: commentCount ?? 0});
143→  };
144→
145→  const handleBookmark = (journalId: string) => {
146→    bookmarkMutation.mutate(journalId);
147→  };
148→
149→  const handleRepost = (journalId: string) => {
150→    Alert.alert('Repost', 'Repost this to your feed?', [
151→      {text: 'Cancel', style: 'cancel'},
152→      {text: 'Repost', onPress: () => repostMutation.mutate(journalId)},
153→    ]);
154→  };
155→
156→  const posts = useMemo(
157→    () => feedQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
158→    [feedQuery.data?.pages],
159→  );
160→
161→  const onRefresh = async () => {
162→    setRefreshing(true);
163→    try {
164→      await feedQuery.refetch();
165→    } finally {
166→      setRefreshing(false);
167→    }
168→  };
169→
170→  const handleQuickAction = (key: string) => {
171→    if (key === 'canvas') {
172→      navigation.navigate('Canvas');
173→    } else if (key === 'freedom_wall') {
174→      navigation.navigate('FreedomWall');
175→    } else if (key === 'universe') {
176→      navigation.navigate('Universe');
177→    } else {
178→      setActiveFilter(key);
179→    }
180→  };
181→
182→  return (
183→    <SafeAreaView
184→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
185→      edges={['top']}>
186→      {/* Branded header */}
187→      <View
188→        style={[
189→          styles.header,
190→          {borderBottomColor: colors.borderCard},
191→        ]}>
192→        <Text style={[styles.brandText, {color: colors.textHeading}]}>
193→          iskrib
194→        </Text>
195→      </View>
196→
197→      {/* Filter chips */}
198→      <View style={styles.chipRow}>
199→        <ScrollView
200→          horizontal
201→          showsHorizontalScrollIndicator={false}
202→          contentContainerStyle={styles.chipScroll}>
203→          {QUICK_ACTIONS.map(action => (
204→            <Chip
205→              key={action.key}
206→              label={action.label}
207→              active={activeFilter === action.key}
208→              onPress={() => handleQuickAction(action.key)}
209→            />
210→          ))}
211→        </ScrollView>
212→      </View>
213→
214→      {/* Feed */}
215→      <FlatList
216→        data={posts}
217→        onRefresh={onRefresh}
218→        refreshing={refreshing}
219→        onEndReachedThreshold={0.25}
220→        onEndReached={() => {
221→          if (feedQuery.hasNextPage && !feedQuery.isFetchingNextPage) {
222→            feedQuery.fetchNextPage();
223→          }
224→        }}
225→        contentContainerStyle={styles.listContent}
226→        showsVerticalScrollIndicator={false}
227→        ListEmptyComponent={
228→          feedQuery.isLoading ? (
229→            <View style={styles.skeletonList}>
230→              <PostCardSkeleton />
231→              <PostCardSkeleton />
232→              <PostCardSkeleton />
233→            </View>
234→          ) : (
235→            <EmptyState
236→              title="No posts yet"
237→              subtitle="Pull to refresh or create your first journal post."
238→            />
239→          )
240→        }
241→        ListFooterComponent={
242→          feedQuery.isFetchingNextPage ? (
243→            <View style={styles.loadingMore}>
244→              <PostCardSkeleton />
245→            </View>
246→          ) : null
247→        }
248→        keyExtractor={item => item.id}
249→        renderItem={({item}) => {
250→          const preview = extractPlainText(item.content).slice(0, 180);
251→          const likeCount = resolveCount(
252→            item.like_count,
253→            item.likes_count,
254→          );
255→          const commentCount = resolveCount(
256→            item.comment_count,
257→            item.comments_count,
258→          );
259→          const bookmarkCount = resolveCount(item.bookmark_count);
260→          const bannerImage = extractBannerImage(
261→            item.content,
262→            (item as any).images,
263→          );
264→
265→          const receiverId = item.user_id ?? item.users?.id ?? '';
266→
267→          const handleAuthorPress = () => {
268→            const authorId = item.users?.id ?? item.user_id;
269→            if (!authorId) return;
270→            if (authorId === user?.id) {
271→              navigation.navigate('Main' as any, {screen: 'Profile'});
272→            } else {
273→              navigation.navigate('VisitProfile', {
274→                userId: authorId,
275→                username: item.users?.username ?? undefined,
276→              });
277→            }
278→          };
279→
280→          return (
281→            <PostCard
282→              title={item.title || 'Untitled Post'}
283→              bodyPreview={preview || 'No preview text available.'}
284→              authorName={item.users?.name || 'Unknown author'}
285→              authorAvatar={item.users?.image_url}
286→              authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
287→              bannerImage={bannerImage}
288→              postType={item.post_type}
289→              likeCount={likeCount}
290→              commentCount={commentCount}
291→              bookmarkCount={bookmarkCount}
292→              userReaction={item.user_reaction}
293→              isBookmarked={!!item.has_bookmarked}
294→              onReact={type => handleReact(item.id, receiverId, type)}
295→              onComment={() => handleComment(item.id, receiverId, commentCount)}
296→              onBookmark={() => handleBookmark(item.id)}
297→              onRepost={() => handleRepost(item.id)}
298→              onPress={() =>
299→                navigation.navigate('PostDetail', {journalId: item.id})
300→              }
301→              onAuthorPress={handleAuthorPress}
302→            />
303→          );
304→        }}
305→        ItemSeparatorComponent={() => <View style={styles.separator} />}
306→      />
307→
308→      {commentModal && (
309→        <CommentModal
310→          visible
311→          postId={commentModal.postId}
312→          receiverId={commentModal.receiverId}
313→          commentCount={commentModal.commentCount}
314→          onClose={() => setCommentModal(null)}
315→        />
316→      )}
317→
318→      {/* FAB Write Button */}
319→      <Pressable
320→        onPress={() => navigation.navigate('JournalEditor', {mode: 'create'})}
321→        style={({pressed}) => [
322→          styles.fab,
323→          {backgroundColor: colors.accentAmber},
324→          shadows(colors).elevated,
325→          pressed && styles.fabPressed,
326→        ]}>
327→        <PenIcon size={22} color="#1A1612" />
328→      </Pressable>
329→    </SafeAreaView>
330→  );
331→}
