  1→import React, {useMemo, useState} from 'react';
  2→import {Alert, FlatList, StyleSheet, View} from 'react-native';
  3→import {useInfiniteQuery, useMutation} from '@tanstack/react-query';
  4→import {useNavigation} from '@react-navigation/native';
  5→import type {NativeStackNavigationProp} from '@react-navigation/native-stack';
  6→import {PostCard} from '../../components/PostCard/PostCard';
  7→import {PostCardSkeleton} from '../../components/SkeletonLoader';
  8→import {CommentModal} from '../../components/Comments';
  9→import {EmptyState} from '../../components/EmptyState';
 10→import {
 11→  extractPlainText,
 12→  extractBannerImage,
 13→  resolveCount,
 14→  getNextCursor,
 15→} from '../../lib/utils/journalHelpers';
 16→import {mobileApi, type CursorPage, type JournalItem} from '../../lib/api/mobileApi';
 17→import {socialApi} from '../../lib/api/socialApi';
 18→import {queryClient} from '../../lib/queryClient';
 19→import {useAuth} from '../../features/auth/AuthProvider';
 20→import {useBookmarkMutation, useRepostMutation} from '../../hooks/useSocialMutations';
 21→import {spacing} from '../../theme/spacing';
 22→import type {RootStackParamList} from '../../navigation/types';
 23→
 24→const PAGE_SIZE = 10;
 25→
 26→interface ProfileWritingsTabProps {
 27→  userId: string;
 28→  headerComponent?: React.ReactElement;
 29→}
 30→
 31→export function ProfileWritingsTab({userId, headerComponent}: ProfileWritingsTabProps) {
 32→  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();
 33→  const {user, session} = useAuth();
 34→  const token = session?.access_token ?? '';
 35→  const [commentModal, setCommentModal] = useState<{postId: string; receiverId?: string; commentCount: number} | null>(null);
 36→
 37→  const query = useInfiniteQuery({
 38→    queryKey: ['profileWritings', userId],
 39→    queryFn: ({pageParam}) =>
 40→      mobileApi.getUserJournals(token, userId, pageParam ?? null, PAGE_SIZE),
 41→    initialPageParam: null as string | null,
 42→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 43→  });
 44→
 45→  const queryKey = ['profileWritings', userId];
 46→
 47→  const reactionMutation = useMutation<
 48→    {message?: string},
 49→    Error,
 50→    {journalId: string; receiverId: string; reactionType: string},
 51→    {prev?: {pages: CursorPage<JournalItem>[]}}
 52→  >({
 53→    mutationFn: async ({journalId, receiverId, reactionType}) => {
 54→      if (!token) throw new Error('Please log in to react.');
 55→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 56→    },
 57→    onMutate: async ({journalId, reactionType}) => {
 58→      await queryClient.cancelQueries({queryKey});
 59→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(queryKey);
 60→      if (prev) {
 61→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(queryKey, old => {
 62→          if (!old) return old;
 63→          return {
 64→            ...old,
 65→            pages: old.pages.map(page => ({
 66→              ...page,
 67→              data: page.data.map(item => {
 68→                if (item.id !== journalId) return item;
 69→                const removing = item.user_reaction === reactionType;
 70→                const currentCount =
 71→                  (item.reaction_count?.[0]?.count ??
 72→                    item.like_count?.[0]?.count ??
 73→                    item.likes_count ??
 74→                    0) as number;
 75→                const delta = removing ? -1 : item.user_reaction ? 0 : 1;
 76→                return {
 77→                  ...item,
 78→                  user_reaction: removing ? null : reactionType,
 79→                  has_liked: removing ? false : true,
 80→                  like_count: [{count: Math.max(0, currentCount + delta)}],
 81→                };
 82→              }),
 83→            })),
 84→          };
 85→        });
 86→      }
 87→      return {prev};
 88→    },
 89→    onError: (_err, _vars, context) => {
 90→      if (context?.prev) {
 91→        queryClient.setQueryData(queryKey, context.prev);
 92→      }
 93→    },
 94→    onSettled: () => {
 95→      queryClient.invalidateQueries({queryKey});
 96→    },
 97→  });
 98→
 99→  const bookmarkMutation = useBookmarkMutation(token, queryKey);
100→  const repostMutation = useRepostMutation(token);
101→
102→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
