  // ... other params
  onRepost,
  // ... other params
}: PostCardProps) {
  // ... 
  return (
    <Pressable // ... >
      {/* ... */}
      <ActionBar
        // ... other props
        onRepost={onRepost}
        // ... other props
      />
    </Pressable>
  );
}
```

**ActionBar Implementation (lines 130-132):**
```typescript
<Pressable style={styles.action} onPress={onRepost} hitSlop={8}>
  <RepostIcon size={18} color={colors.iconDefault} />
</Pressable>
```

The repost button is a simple `Pressable` component with a `RepostIcon` that calls the `onRepost` callback when pressed.

---

### 5. **useRepostMutation Hook**

**Location:** `C:\Users\johnm\iskrib_mobile_app\apps\mobile\src\hooks\useSocialMutations.ts` (lines 54-68)

```typescript
export function useRepostMutation(token: string) {
  return useMutation({
    mutationFn: async (sourceJournalId: string) => {
      if (!token) throw new Error('Please log in to repost.');
      return socialApi.createRepost(token, {sourceJournalId});
    },
    onSuccess: () => {
      Alert.alert('Reposted', 'This post has been shared to your feed.');
      queryClient.invalidateQueries({queryKey: ['feed']});
    },
    onError: () => {
      Alert.alert('Error', 'Could not repost. Please try again.');
    },
  });
}
```

Used in HomeFeedScreen and ProfileWritingsTab. It:
- Takes only the `sourceJournalId` (no caption from simple repost flow)
- Shows success/error alerts
- Invalidates the feed cache on success

---

## Key Differences Summary

| Component | Repost Flow |
|-----------|------------|
| **HomeFeedScreen / ProfileWritingsTab** | Simple alert confirmation → no caption option → uses hook |
| **PostDetailScreen** | Full UI with caption input (max 280 chars) → optional caption → direct mutation |
| **Payload** | Quick repost: `{sourceJournalId}` | Detail page: `{sourceJournalId, caption?}` |

All paths ultimately call `socialApi.createRepost(token, {sourceJournalId, caption?})` which POSTs to `/repost` endpoint.
